import{_ as t,o as r,c as i,a2 as a}from"./chunks/framework.Crpw6aS5.js";const g=JSON.parse('{"title":"Règles automatiques","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/rules.md","filePath":"fr/guide/rules.md"}'),o={name:"fr/guide/rules.md"};function l(s,e,n,d,u,c){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="regles-automatiques" tabindex="-1">Règles automatiques <a class="header-anchor" href="#regles-automatiques" aria-label="Permalink to &quot;Règles automatiques&quot;">​</a></h1><p>Les règles vous permettent d&#39;automatiser le nettoyage et l&#39;organisation de votre boîte Gmail. Définissez des conditions et des actions — Nid les exécute pour vous.</p><hr><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>Une règle se compose de :</p><ul><li><strong>Conditions</strong> : quels mails cibler (expéditeur, objet, taille, etc.)</li><li><strong>Action</strong> : que faire avec ces mails (supprimer, archiver, labelliser, etc.)</li><li><strong>Planification</strong> : quand exécuter la règle (manuellement, quotidiennement, hebdomadairement, etc.)</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Règles avec la liste des règles configurées (nom, conditions résumées, action, planification, toggle actif/inactif)</em></p></blockquote><hr><h2 id="creer-une-regle" tabindex="-1">Créer une règle <a class="header-anchor" href="#creer-une-regle" aria-label="Permalink to &quot;Créer une règle&quot;">​</a></h2><ol><li>Dans <strong>Règles</strong>, cliquez sur <strong>Créer une règle</strong></li><li>Renseignez les champs du formulaire</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : formulaire de création de règle (modal) avec les champs conditions, action et planification</em></p></blockquote><h3 id="conditions" tabindex="-1">Conditions <a class="header-anchor" href="#conditions" aria-label="Permalink to &quot;Conditions&quot;">​</a></h3><p>Vous pouvez combiner plusieurs conditions. <strong>Toutes les conditions</strong> doivent être remplies pour qu&#39;un mail soit ciblé (logique ET).</p><table tabindex="0"><thead><tr><th>Champ</th><th>Description</th><th>Exemple</th></tr></thead><tbody><tr><td><code>from</code></td><td>Expéditeur</td><td><code>newsletter@example.com</code></td></tr><tr><td><code>to</code></td><td>Destinataire</td><td><code>mon-alias@gmail.com</code></td></tr><tr><td><code>subject</code></td><td>Objet du mail</td><td><code>promotion</code></td></tr><tr><td><code>has_attachment</code></td><td>Présence de pièce jointe</td><td><code>true</code> / <code>false</code></td></tr><tr><td><code>size_gt</code></td><td>Taille minimale (en octets)</td><td><code>5242880</code> (5 Mo)</td></tr><tr><td><code>older_than</code></td><td>Ancienneté minimale</td><td><code>30d</code>, <code>6m</code>, <code>1y</code></td></tr><tr><td><code>label</code></td><td>Label Gmail</td><td><code>INBOX</code>, <code>SPAM</code>, <code>Label_123</code></td></tr><tr><td><code>is_unread</code></td><td>Non lu</td><td><code>true</code> / <code>false</code></td></tr></tbody></table><p>Opérateurs disponibles : <code>contains</code> (contient), <code>equals</code> (exact), <code>not_contains</code> (ne contient pas), <code>gt</code> (supérieur), <code>lt</code> (inférieur).</p><h3 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><strong>Mettre à la corbeille</strong></td><td>Envoie les mails à la corbeille Gmail</td></tr><tr><td><strong>Supprimer définitivement</strong></td><td>Suppression irréversible</td></tr><tr><td><strong>Archiver (Gmail)</strong></td><td>Retire de la boîte de réception</td></tr><tr><td><strong>Archiver sur NAS</strong></td><td>Sauvegarde en EML sur votre NAS</td></tr><tr><td><strong>Ajouter un label</strong></td><td>Applique un label Gmail</td></tr><tr><td><strong>Retirer un label</strong></td><td>Retire un label Gmail</td></tr><tr><td><strong>Marquer comme lu</strong></td><td>Marque les mails comme lus</td></tr><tr><td><strong>Marquer comme non lu</strong></td><td>Marque les mails comme non lus</td></tr></tbody></table><h3 id="planifications" tabindex="-1">Planifications <a class="header-anchor" href="#planifications" aria-label="Permalink to &quot;Planifications&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Manuel</strong></td><td>Exécution uniquement à la demande</td></tr><tr><td><strong>Toutes les heures</strong></td><td>S&#39;exécute chaque heure</td></tr><tr><td><strong>Quotidien</strong></td><td>S&#39;exécute une fois par jour</td></tr><tr><td><strong>Hebdomadaire</strong></td><td>S&#39;exécute chaque lundi</td></tr><tr><td><strong>Mensuel</strong></td><td>S&#39;exécute le 1er de chaque mois</td></tr></tbody></table><hr><h2 id="templates-de-regles" tabindex="-1">Templates de règles <a class="header-anchor" href="#templates-de-regles" aria-label="Permalink to &quot;Templates de règles&quot;">​</a></h2><p>Pour démarrer rapidement, Nid propose une <strong>bibliothèque de templates</strong> pré-configurés.</p><ol><li>Cliquez sur <strong>Templates</strong> en haut de la page Règles</li><li>Parcourez les modèles par catégorie : <ul><li><strong>Nettoyage</strong> : supprimer les mails promotionnels, les vieilles notifications</li><li><strong>Archive</strong> : archiver les factures, les mails anciens</li><li><strong>Organisation</strong> : labelliser automatiquement par expéditeur</li></ul></li><li>Cliquez sur <strong>Utiliser</strong> sur un template</li><li>La règle est créée — modifiez-la si nécessaire puis activez-la</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : drawer/panneau des templates de règles avec les 3 catégories</em></p></blockquote><p>Exemples de templates :</p><ul><li>&quot;Nettoyer les notifications GitHub &gt; 30 jours&quot;</li><li>&quot;Archiver les factures de plus de 3 mois&quot;</li><li>&quot;Supprimer les newsletters non lues &gt; 30 jours&quot;</li></ul><hr><h2 id="previsualiser-une-regle" tabindex="-1">Prévisualiser une règle <a class="header-anchor" href="#previsualiser-une-regle" aria-label="Permalink to &quot;Prévisualiser une règle&quot;">​</a></h2><p>Avant d&#39;exécuter une règle, vous pouvez la <strong>prévisualiser</strong> :</p><ol><li>Cliquez sur <strong>Prévisualiser</strong> sur une règle existante</li><li>Nid affiche la liste des mails qui correspondent aux conditions</li><li>Vérifiez que les mails ciblés sont bien ceux que vous attendez</li><li>Cliquez sur <strong>Exécuter</strong> pour lancer la règle</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : résultat de la prévisualisation d&#39;une règle avec la liste des mails qui matchent</em></p></blockquote><hr><h2 id="executer-une-regle" tabindex="-1">Exécuter une règle <a class="header-anchor" href="#executer-une-regle" aria-label="Permalink to &quot;Exécuter une règle&quot;">​</a></h2><h3 id="execution-manuelle" tabindex="-1">Exécution manuelle <a class="header-anchor" href="#execution-manuelle" aria-label="Permalink to &quot;Exécution manuelle&quot;">​</a></h3><p>Cliquez sur <strong>Exécuter</strong> sur une règle pour la lancer immédiatement. Un job est créé avec suivi en temps réel.</p><h3 id="execution-planifiee" tabindex="-1">Exécution planifiée <a class="header-anchor" href="#execution-planifiee" aria-label="Permalink to &quot;Exécution planifiée&quot;">​</a></h3><p>Si une planification est configurée (quotidien, hebdomadaire, etc.), la règle s&#39;exécute automatiquement. Le champ <strong>Dernière exécution</strong> indique quand la règle a été exécutée pour la dernière fois.</p><hr><h2 id="activer-desactiver-une-regle" tabindex="-1">Activer / désactiver une règle <a class="header-anchor" href="#activer-desactiver-une-regle" aria-label="Permalink to &quot;Activer / désactiver une règle&quot;">​</a></h2><p>Le <strong>toggle</strong> à côté de chaque règle permet de l&#39;activer ou la désactiver sans la supprimer. Une règle désactivée n&#39;est pas exécutée lors des planifications automatiques.</p><hr><h2 id="modifier-et-supprimer" tabindex="-1">Modifier et supprimer <a class="header-anchor" href="#modifier-et-supprimer" aria-label="Permalink to &quot;Modifier et supprimer&quot;">​</a></h2><ul><li>Cliquez sur une règle pour ouvrir le formulaire d&#39;édition</li><li>Le bouton <strong>Supprimer</strong> supprime définitivement la règle</li></ul>',43)])])}const p=t(o,[["render",l]]);export{g as __pageData,p as default};
